function(x)
{
  sites <- unique(x$SiteID)
  years <- unique(x$Year)
  result <- data.frame()
  x$ID <- seq(1,nrow(x))
  for (i in 1:length(sites))
  {
    for (j in 1:length(years))
    {
      if (nrow(x[as.character(x$SiteID)==as.character(sites[i]) &
x$Year==years[j],]) > 3)
      {
        sampledID <- sample(x[as.character(x$SiteID)==as.character(sites[i])
