        for (k in 1:length(sampledID))
        {
          result <- rbind(result,x[x$ID==sampledID[k],-4])
        }          
      }
    }
  }
  names(result) <- c("IDbyYear","SiteID","Year")
  rownames(result) <- NULL
  return(result)
